// Build Gmail search query from WRM webhook params
// Input: { dateFrom, dateTo, senderContains, subjectContains, limit }
const body = $input.first().json.body || $input.first().json;

const dateFrom = body.dateFrom;
const dateTo   = body.dateTo;
const sender   = (body.senderContains  || '').trim();
const subject  = (body.subjectContains || '').trim();
const limit    = Math.min(parseInt(body.limit, 10) || 10, 10);

function toGmailDate(iso) {
  const d = new Date(iso);
  return `${d.getUTCFullYear()}/${String(d.getUTCMonth()+1).padStart(2,'0')}/${String(d.getUTCDate()).padStart(2,'0')}`;
}

// Gmail 'before' is exclusive — bump +1 day to include the full dateTo day
const exclusiveTo = new Date(dateTo);
exclusiveTo.setUTCDate(exclusiveTo.getUTCDate() + 1);

const parts = [
  `after:${toGmailDate(dateFrom)}`,
  `before:${toGmailDate(exclusiveTo.toISOString())}`,
];
if (sender)  parts.push(`from:${sender}`);
if (subject) parts.push(`subject:${subject}`);

return [{ json: { searchQuery: parts.join(' '), limit } }];

// Normalize Gmail output to match Outlook/Graph API shape.
// Handles three formats the Gmail node may return:
//   1. headers object with prefixed values: { headers: { subject: 'Subject: ...', from: 'From: ...' } }
//   2. direct fields (simple format): { subject: '...', from: '...' }
//   3. payload.headers array (raw format): { payload: { headers: [{ name, value }] } }
return $input.all().map(item => {
  const m = item.json;

  // Strip 'HeaderName: ' prefix if present
  function stripPrefix(val) {
    if (!val) return null;
    const colon = String(val).indexOf(':');
    if (colon === -1) return String(val).trim();
    return String(val).slice(colon + 1).trim();
  }

  // Try direct field, headers object, then payload.headers array
  function getField(name) {
    const key = name.toLowerCase();
    // 1. Direct field
    if (m[key] !== undefined && m[key] !== null && m[key] !== '') return m[key];
    // 2. Headers object (n8n Gmail node default output)
    if (m.headers && m.headers[key]) return stripPrefix(m.headers[key]);
    // 3. Payload headers array (raw Gmail API format)
    const hdrs = (m.payload && m.payload.headers) || [];
    const h = hdrs.find(h => h.name && h.name.toLowerCase() === key);
    if (h && h.value) return h.value;
    return null;
  }

  // Parse 'Name <email>' or plain email
  const fromStr = getField('from') || '';
  const match = fromStr.match(/^(.+?)\s*<([^>]+)>\s*$/);
  const fromName    = match ? match[1].trim() : fromStr;
  const fromAddress = match ? match[2].trim() : fromStr;

  // Date → ISO string
  let receivedDateTime = null;
  const dateStr = getField('date');
  if (dateStr) {
    try { receivedDateTime = new Date(dateStr).toISOString(); } catch(e) {}
  }
  // Fall back to internalDate (milliseconds since epoch as string)
  if (!receivedDateTime && m.internalDate) {
    receivedDateTime = new Date(parseInt(m.internalDate, 10)).toISOString();
  }

  const bodyContent = m.textPlain || m.textHtml || m.text || m.html || '';

  return {
    json: {
      internetMessageId: `gmail:${m.id}`,
      subject:           getField('subject'),
      receivedDateTime,
      hasAttachments:    Array.isArray(m.attachments) && m.attachments.length > 0,
      body: {
        contentType: (m.textPlain || m.text) ? 'text' : 'html',
        content:     bodyContent,
      },
      from: {
        emailAddress: {
          name:    fromName || fromAddress,
          address: fromAddress,
        },
      },
    },
  };
});
